#include <iostream>
#include <cstdio>
#include <cstring>
using namespace std;

struct DoublyListNode {
    int val;
    DoublyListNode* prev;
    DoublyListNode* next;

    DoublyListNode(int x) : val(x), prev(nullptr), next(nullptr) {}
};

class Solution {
public:
    void solve(DoublyListNode* head1, DoublyListNode* head2) {
        DoublyListNode* newHead1 = head1;
        DoublyListNode* newHead2 = head2;

        while (newHead1 && newHead2) {
            if (newHead1->val < newHead2->val) {
                newHead1 = newHead1->next;
            } else {
                newHead2 = newHead2->next;
            }
        }

        if (newHead1) {
            while (newHead1->next) {
                newHead1 = newHead1->next;
            }
            newHead1->next = head2;
        } else {
            while (newHead2->next) {
                newHead2 = newHead2->next;
            }
            newHead2->next = head1;
        }

        return;
    }
};

